/// <summary>
/// UI Builder class for the quota contract line generation process for the ETGSPAIN model.
/// </summary>
class ETGSPAINPurchSalesAgreementQuotaDialogUIBuilder extends SysOperationAutomaticUIBuilder
{
    private DialogField dlgFromDate;
    private DialogField dlgToDate;
    private DialogField dlgPeriods;

}

Method.Source:
/// <summary>
/// Overrides the <c>postBuild</c> method to add customizations to the dialog UI.
/// </summary>
public void postBuild()
{
    super();

    dlgFromDate = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGSPAINPurchSalesAgreementQuotaDialogContract,parmQuotaFromDate));
    dlgToDate = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGSPAINPurchSalesAgreementQuotaDialogContract,parmQuotaToDate));
    dlgPeriods = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGSPAINPurchSalesAgreementQuotaDialogContract,parmQuotaPeriods));
    dlgPeriods.allowEdit(false);

    this.reCalcPeriods();

    dlgFromDate.registerOverrideMethod(methodStr(FormDateControl, modified), methodStr(ETGSPAINPurchSalesAgreementQuotaDialogUIBuilder , fromDateModified), this);
    dlgToDate.registerOverrideMethod(methodStr(FormDateControl, modified), methodStr(ETGSPAINPurchSalesAgreementQuotaDialogUIBuilder , toDateModified), this);
}

/// <summary>
/// Handler for the modification of the "From Date" field.
/// </summary>
/// <param name = "_control">Form date control element.</param>
/// <returns>Boolean value indicating whether the field was successfully modified.</returns>
public boolean fromDateModified(FormDateControl _control)
{
    dlgFromDate.value(_control.dateValue());

    this.reCalcPeriods();

    return true;
}

/// <summary>
/// Handler for the modification of the "To Date" field.
/// </summary>
/// <param name = "_control">Form date control element.</param>
/// <returns>Boolean value indicating whether the field was successfully modified.</returns>
public boolean toDateModified(FormDateControl _control)
{
    dlgToDate.value(_control.dateValue());

    this.reCalcPeriods();

    return true;
}

/// <summary>
/// Recalculates the number of periods (in months) between the "From Date" and "To Date" fields.
/// </summary>
public void reCalcPeriods()
{
    dlgPeriods.value(intvNo(dlgToDate.value(), dlgFromDate.value(), intvScale::YearMonth) + 1);
}
